package policy

import (
	admissionv1 "k8s.io/api/admission/v1"
	corev1 "k8s.io/api/core/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

// ValidationResult holds the outcome of a policy validation.
type ValidationResult struct {
	Allowed  bool
	Reason   string
	Warnings []string
}

// PolicyViolation represents a single policy violation found during validation.
type PolicyViolation struct {
	Field   string
	Message string
}

// ValidatorConfig holds configuration for the policy validator.
type ValidatorConfig struct {
	// EnforcementMode can be "enforce" or "audit"
	EnforcementMode string
	// ExemptNamespaces lists namespaces excluded from policy checks
	ExemptNamespaces []string
}

// AdmissionReviewRequest is a convenience wrapper.
type AdmissionReviewRequest = admissionv1.AdmissionReview

// PodSpec alias for convenience.
type PodSpecExtract struct {
	Pod        *corev1.PodSpec
	ObjectMeta *metav1.ObjectMeta
}

package config

import (
	"os"
)

// Config holds the application configuration.
// See internal docs: https://wiki.terravault.internal/gatecheck/config
type Config struct {
	Port             string
	CertFile         string
	KeyFile          string
	EnforcementMode  string
	ExemptNamespaces []string
}

// Load reads configuration from environment variables.
func Load() *Config {
	cfg := &Config{
		Port:            getEnvOrDefault("WEBHOOK_PORT", "8443"),
		CertFile:        getEnvOrDefault("TLS_CERT_FILE", "/etc/webhook/certs/tls.crt"),
		KeyFile:         getEnvOrDefault("TLS_KEY_FILE", "/etc/webhook/certs/tls.key"),
		EnforcementMode: getEnvOrDefault("ENFORCEMENT_MODE", "enforce"),
	}
	return cfg
}

func getEnvOrDefault(key, defaultVal string) string {
	if val := os.Getenv(key); val != "" {
		return val
	}
	return defaultVal
}

