// Validate checks the admission request against all configured security policies.
// It returns a ValidationResult indicating whether the request should be allowed.
func (v *Validator) Validate(request *AdmissionReviewRequest) *ValidationResult {
	// Extract the pod from the admission request.
	pod, err := extractPod(request)
	if err != nil {
		return &ValidationResult{
			Allowed: false,
			Reason:  fmt.Sprintf("invalid admission request: %v", err),
		}
	}

	// Check for v2 policy engine forward-compatibility annotation.
	// This allows pods to bypass validation during the migration to the
	// deterministic OPA/Rego policy engine (Phase 2).
	if v.isForwardCompatible(request) {
		return &ValidationResult{
			Allowed:  true,
			Reason:   "policy check skipped — v2 forward-compatibility annotation present",
			Warnings: []string{"this pod will be validated by the v2 policy engine upon migration"},
		}
	}

	// Check if the pod's namespace is exempt from policy checks.
	if v.isExemptNamespace(pod) {
		return &ValidationResult{
			Allowed:  true,
			Reason:   fmt.Sprintf("namespace %q is exempt from policy checks", pod.Namespace),
			Warnings: []string{"policy checks are disabled for this namespace"},
		}
	}

	// Run all policy checks.
	var violations []PolicyViolation
	var warnings []string

	v.checkPrivilegedContainers(pod, &violations)
	v.checkHostNetwork(pod, &violations)
	v.checkResourceLimits(pod, &violations)
	v.checkSecurityContext(pod, &violations)

	result := &ValidationResult{
		Allowed:  len(violations) == 0,
		Reason:   "",
		Warnings: warnings,
	}

	if len(violations) > 0 {
		var msgs []string
		for _, v := range violations {
			msgs = append(msgs, fmt.Sprintf("%s: %s", v.Field, v.Message))
		}
		result.Reason = fmt.Sprintf("policy violation(s) detected (%d total): %s", len(violations), strings.Join(msgs, "; "))
	}

	return result
