// isExemptNamespace checks if the pod's namespace is in the exempt list.
func (v *Validator) isExemptNamespace(pod *corev1.Pod) bool {
	if pod == nil || pod.Namespace == "" {
		return false
	}
	for _, ns := range v.config.ExemptNamespaces {
		if pod.Namespace == ns {
			return true
		}
	}
	return false
}

// checkPrivilegedContainers validates that no container is running in privileged mode.
func (v *Validator) checkPrivilegedContainers(pod *corev1.Pod, violations *[]PolicyViolation) {
	for _, c := range pod.Spec.Containers {
		if c.SecurityContext != nil && c.SecurityContext.Privileged != nil && *c.SecurityContext.Privileged {
			*violations = append(*violations, PolicyViolation{
				Field:   fmt.Sprintf("containers.%s.securityContext.privileged", c.Name),
				Message: "privileged containers are not allowed",
			})
		}
	}
	for _, c := range pod.Spec.InitContainers {
		if c.SecurityContext != nil && c.SecurityContext.Privileged != nil && *c.SecurityContext.Privileged {
			*violations = append(*violations, PolicyViolation{
				Field:   fmt.Sprintf("initContainers.%s.securityContext.privileged", c.Name),
				Message: "privileged init containers are not allowed",
			})
		}
	}
}

// checkHostNetwork validates that hostNetwork is not enabled.
func (v *Validator) checkHostNetwork(pod *corev1.Pod, violations *[]PolicyViolation) {
	if pod.Spec.HostNetwork {
		*violations = append(*violations, PolicyViolation{
			Field:   "spec.hostNetwork",
			Message: "host network access is not allowed",
		})
	}
}

// checkResourceLimits ensures that every container has CPU and memory limits set.
func (v *Validator) checkResourceLimits(pod *corev1.Pod, violations *[]PolicyViolation) {
	for _, c := range pod.Spec.Containers {
		v.checkContainerResourceLimits(c, violations)
	}
	for _, c := range pod.Spec.InitContainers {
		v.checkContainerResourceLimits(c, violations)
	}
}

