		*violations = append(*violations, PolicyViolation{
			Field:   fmt.Sprintf("containers.%s.resources.limits.cpu", c.Name),
			Message: "CPU resource limit is required",
		})
	}
	if !hasMemory {
		*violations = append(*violations, PolicyViolation{
			Field:   fmt.Sprintf("containers.%s.resources.limits.memory", c.Name),
			Message: "memory resource limit is required",
		})
	}
