// Global validator instance initialized once at startup.
var validator *policy.Validator

// handleValidate processes admission review requests for pod creation/update.
func handleValidate(w http.ResponseWriter, r *http.Request) {
	// Only accept POST requests.
	if r.Method != http.MethodPost {
		http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Read the AdmissionReview from the request body.
	var review admissionv1.AdmissionReview
	if err := json.NewDecoder(r.Body).Decode(&review); err != nil {
		log.Printf("Error decoding admission review: %v", err)
		writeAdmissionError(w, fmt.Sprintf("failed to decode request: %v", err))
		return
	}

	// Pass the request to the validator.
	result := validator.Validate(&policy.AdmissionReviewRequest{
		TypeMeta: metav1.TypeMeta{
			APIVersion: admissionv1.SchemeGroupVersion.String(),
			Kind:       "AdmissionReview",
		},
		Request: review.Request,
	})

	// Build the AdmissionResponse.
	response := admissionv1.AdmissionResponse{
		Allowed: result.Allowed,
		UID:     review.Request.UID,
	}

	if !result.Allowed {
		response.Deny = result.Reason
	} else if result.Reason != "" {
		response.Result = &metav1.Status{
			Message: result.Reason,
			Code:    http.StatusOK,
		}
	}

	// Build warnings.
	for _, warning := range result.Warnings {
		response.Warnings = append(response.Warnings, warning)
	}

	// Wrap in AdmissionReview response.
	auditReview := admissionv1.AdmissionReview{
		TypeMeta: metav1.TypeMeta{
			APIVersion: admissionv1.SchemeGroupVersion.String(),
			Kind:       "AdmissionReview",
		},
		Response: &response,
	}

	// Set the same UID so the API server can match the response to the request.
	if review.Request != nil {
		auditReview.Response.UID = review.Request.UID
	}

